mapper.select:
SELECT o.*, u.username, u.phone as user_phone, e.name as equipment_name, e.image as equipment_image, CASE o.status WHEN 'pending' THEN '待支付' WHEN 'paid' THEN '已支付' WHEN 'renting' THEN '租赁中' WHEN 'completed' THEN '已完成' WHEN 'cancelled' THEN '已取消' WHEN 'overdue' THEN '已逾期' END as status_text, CASE o.payment_status WHEN 'unpaid' THEN '未支付' WHEN 'paid' THEN '已支付' WHEN 'refunded' THEN '已退款' END as payment_status_text, CASE o.deposit_deduction_status WHEN 'none' THEN '无扣除' WHEN 'pending' THEN '待扣除' WHEN 'deducted' THEN '已扣除' WHEN 'rejected' THEN '已拒绝' END as deposit_deduction_status_text, COALESCE(d.delivery_type, 1) as delivery_type, COALESCE(CASE d.delivery_type WHEN 1 THEN '自提' WHEN 2 THEN '配送到家' WHEN 3 THEN '上门取件' END, '自提') as delivery_type_text, d.delivery_no, d.recipient_name, d.recipient_phone, d.recipient_address, d.contact_name, d.contact_phone, d.pickup_address FROM db_order o LEFT JOIN db_account u ON o.user_id = u.id LEFT JOIN db_equipment e ON o.equipment_id = e.id LEFT JOIN db_delivery d ON o.order_no = d.order_no
1=1
AND o.user_id = #{userId}
AND o.status = #{query.status}
AND o.payment_status = #{query.paymentStatus}
ORDER BY o.create_time DESC

mapper.update:
UPDATE db_order
SET delivery_no = #{deliveryNo}
WHERE id = #{orderId}

UPDATE db_order
SET deposit_deduction_status = #{status},
    deducted_amount = #{amount}
WHERE id = #{orderId}
